using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();

var app = builder.Build();

// Train model at startup and register prediction pool
var trainer = app.Services.GetRequiredService<ModelTrainingService>();
trainer.TrainAndEvaluate();

// Re-register services with the trained model path for PredictionEnginePool
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(trainer.ModelPath);

// Rebuild with prediction pool registered
builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>()
    .FromFile(Path.Combine(builder.Environment.ContentRootPath, "Data", "model.zip"));

app = builder.Build();

// Train on first startup (model file may not exist yet)
var trainingService = app.Services.GetRequiredService<ModelTrainingService>();
if (!File.Exists(trainingService.ModelPath))
{
    trainingService.TrainAndEvaluate();
}

app.MapControllers();
app.Run();

