1. using Microsoft.ML;
2. using TicketClassifier.Models;
3. 
4. namespace TicketClassifier.Services;
5. 
6. public class ModelTrainingService
7. {
8.     private readonly string _dataPath;
9.     private readonly string _modelPath;
10.     private readonly ILogger<ModelTrainingService> _logger;
11. 
12.     public ModelTrainingService(ILogger<ModelTrainingService> logger, IWebHostEnvironment env)
13.     {
14.         _dataPath = Path.Combine(env.ContentRootPath, "Data", "tickets.csv");
15.         _modelPath = Path.Combine(env.ContentRootPath, "Data", "model.zip");
16.         _logger = logger;
17.     }
18. 
19.     public string ModelPath => _modelPath;
20. 
21.     public void TrainAndEvaluate()
22.     {
23.         var mlContext = new MLContext(seed: 42);
24. 
25.         // Load data
26.         var data = mlContext.Data.LoadFromTextFile<TicketInput>(
27.             _dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);
28. 
29.         // Split into train/test sets
30.         var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);
31. 
32.         // Build pipeline: featurize text + combine with priority + classify
33.         var pipeline = mlContext.Transforms.Text.FeaturizeText(
34.                 outputColumnName: "SubjectFeaturized", inputColumnName: nameof(TicketInput.Subject))
35.             .Append(mlContext.Transforms.Text.FeaturizeText(
36.                 outputColumnName: "DescriptionFeaturized", inputColumnName: nameof(TicketInput.Description)))
37.             .Append(mlContext.Transforms.Concatenate("Features",
38.                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketInput.Priority)))
39.             .Append(mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketInput.Category)))
40.             .Append(mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy(
